import pytest
import requests
from freezegun import freeze_time

@freeze_time('2025-02-10T10:00:00Z')
def test_schedule_appointment_slot_in_past(auth_token, base_url):
    headers = {'Authorization': f'Bearer {auth_token}'}
    payload = {
        'provider_id': 'DR_001',
        'slot_time': '2025-02-09T14:00:00Z',
        'patient_id': 'PAT_001'
    }
    resp = requests.post(f'{base_url}/appointments', json=payload, headers=headers)
    assert resp.status_code == 422
    body = resp.json()
    assert body['error_code'] == 'SLOT_IN_PAST'

